from enum import Enum
from openai import OpenAI

client = OpenAI()


class AnswerQuality(Enum):
    GOOD = "good"
    UNCERTAIN = "uncertain"  # AI hedged heavily
    REFUSED = "refused"      # AI declined to answer
    EMPTY = "empty"          # no substantive content


REFUSAL_PHRASES = (
    "i cannot", "i can't", "i am not able", "i'm not able",
    "i don't have information", "i'm unable", "as an ai",
)

UNCERTAINTY_PHRASES = (
    "i'm not sure", "i don't know", "i'm uncertain",
    "you may want to verify", "i cannot confirm",
)


def assess_quality(response_text: str) -> AnswerQuality:
    text = response_text.lower().strip()
    if not text or len(text) < 20:
        return AnswerQuality.EMPTY
    if any(phrase in text for phrase in REFUSAL_PHRASES):
        return AnswerQuality.REFUSED
    if any(phrase in text for phrase in UNCERTAINTY_PHRASES):
        return AnswerQuality.UNCERTAIN
    return AnswerQuality.GOOD


FALLBACK_FAQ = {
    "return": "You can return items within 30 days. Visit our returns portal.",
    "shipping": "Standard shipping takes 5–7 business days. Express is 2 days.",
    "refund": "Refunds are processed within 5–10 business days after we receive your return.",
}


def static_fallback(query: str) -> str | None:
    q = query.lower()
    for keyword, answer in FALLBACK_FAQ.items():
        if keyword in q:
            return answer
    return None


def chat_with_quality_fallback(user_message: str) -> dict:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{"role": "user", "content": user_message}],
        max_tokens=256,
    )
    answer = response.choices[0].message.content
    quality = assess_quality(answer)

    if quality == AnswerQuality.GOOD:
        return {"answer": answer, "source": "ai"}

    if quality == AnswerQuality.REFUSED:
        # Check if we have a static fallback
        static = static_fallback(user_message)
        if static:
            return {"answer": static, "source": "faq"}
        return {"answer": None, "escalate": True, "reason": "out_of_scope"}

    if quality in (AnswerQuality.UNCERTAIN, AnswerQuality.EMPTY):
        static = static_fallback(user_message)
        if static:
            return {"answer": static, "source": "faq"}
        return {"answer": answer, "source": "ai", "low_confidence": True}

from dataclasses import dataclass
from typing import Literal


@dataclass
class FallbackResponse:
    type: Literal["faq", "search", "escalate", "clarify"]
    message: str                    # shown to user
    action_label: str | None        # CTA button label
    action_url: str | None          # CTA button URL
    context_for_human: str | None   # passed to human agent if escalating


def build_fallback(reason: str, query: str) -> FallbackResponse:
    """
    reason: 'refused' | 'out_of_scope' | 'all_failed' | 'low_confidence'
    """
    if reason == "out_of_scope":
        return FallbackResponse(
            type="escalate",
            message="I'm not able to help with that through this channel.",
            action_label="Contact support",
            action_url="/support?q=" + query[:200],
            context_for_human=f"User asked: {query}",
        )

    if reason == "all_failed":
        return FallbackResponse(
            type="search",
            message="I'm having trouble right now. Here are some articles that might help:",
            action_label="Search our help centre",
            action_url=f"/help/search?q={query[:100]}",
            context_for_human=None,
        )

    if reason == "low_confidence":
        return FallbackResponse(
            type="clarify",
            message="I want to make sure I give you the right answer — could you tell me more about your situation?",
            action_label=None,
            action_url=None,
            context_for_human=None,
        )

    return FallbackResponse(
        type="faq",
        message="I couldn't find a specific answer, but here are common questions that might help.",
        action_label="Browse FAQs",
        action_url="/faq",
        context_for_human=None,
    )

import json
from datetime import datetime


def create_escalation_ticket(
    conversation_history: list[dict],
    reason: str,
    user_id: str | None = None,
) -> dict:
    """Create a support ticket with full conversation context."""

    # Summarise conversation for the human agent
    summary_prompt = [
        {"role": "system", "content": "Summarise this customer conversation in 3 bullet points for a support agent. Include: what the customer wanted, what the AI tried, and why escalation was needed."},
        {"role": "user", "content": json.dumps(conversation_history[-10:])},  # last 10 turns
    ]
    summary_resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=summary_prompt,
        max_tokens=200,
    )
    agent_summary = summary_resp.choices[0].message.content

    return {
        "ticket": {
            "created_at": datetime.utcnow().isoformat(),
            "user_id": user_id,
            "escalation_reason": reason,
            "agent_summary": agent_summary,
            "full_conversation": conversation_history,
            "priority": "high" if reason == "complaint" else "normal",
        }
    }


# User-facing message when escalating:
def escalation_message(ticket_id: str) -> str:
    return (
        f"I've connected you with a support agent (ticket #{ticket_id}). "
        "They can see our full conversation so you won't need to repeat anything. "
        "You should hear back within 2 hours."
    )
